// ─── HORÁRIOS ─────────────────────────────────────────────────────────────────
const DIAS = ['seg','ter','qua','qui','sex','sab','dom'];
function salvarHorarios() {
  const horarios = {};
  DIAS.forEach(d => {
    horarios[d] = {
      aberto: document.getElementById('h-'+d+'-on')?.checked ?? true,
      abre: document.getElementById('h-'+d+'-a')?.value || '08:00',
      fecha: document.getElementById('h-'+d+'-f')?.value || '22:00'
    };
  });
  if (!currentUser) return;
  currentUser.horarios = horarios;
  saveCurrentUser();
  const db = getSupa();
  if (db && currentUser.id?.includes('-')) {
    db.from('estabelecimentos').update({ horarios: JSON.stringify(horarios) }).eq('id', currentUser.id).then(()=>{});
  }
}

function carregarHorarios() {
  const h = currentUser?.horarios;
  if (!h) return;
  DIAS.forEach(d => {
    const dia = h[d];
    if (!dia) return;
    const on = document.getElementById('h-'+d+'-on');
    const a = document.getElementById('h-'+d+'-a');
    const f = document.getElementById('h-'+d+'-f');
    if (on) on.checked = dia.aberto !== false;
    if (a) a.value = dia.abre || '08:00';
    if (f) f.value = dia.fecha || '22:00';
  });
}

// ─── ÁUDIO DE NOTIFICAÇÃO ─────────────────────────────────────────────────────
const NOTIF_AUDIO_B64 = 'data:audio/mp3;base64,';
let _notifAudio = null;
let _notifTimeout = null;
let _notifOrderId = null;

function tocarSomNovoPedido(orderId) {
  pararSomNotificacao();
  _notifOrderId = orderId || null;
  _iniciarCicloSom();
}

function _iniciarCicloSom() {
  // Verifica se ainda é necessário tocar antes de cada ciclo
  if (_notifOrderId) {
    const ativo = (currentUser?.orders||[]).find(o => o.supaId===_notifOrderId || o.id===_notifOrderId);
    if (!ativo || ativo.status !== 'new') { pararSomNotificacao(); return; }
  }
  // Toca o som e só agenda o próximo ciclo quando ele terminar
  _tocarAudio(() => {
    // Som terminou — aguarda 5 segundos e toca de novo
    _notifTimeout = setTimeout(() => {
      _iniciarCicloSom();
    }, 5000);
  });
}

function _tocarAudio(onEnded) {
  try {
    const a = new Audio(NOTIF_AUDIO_B64);
    a.volume = 0.85;
    _notifAudio = a;
    a.onended = () => { if (onEnded) onEnded(); };
    a.play().catch(() => { if (onEnded) onEnded(); });
  } catch(e) {
    try {
      const ctx = new (window.AudioContext||window.webkitAudioContext)();
      const t = ctx.currentTime;
      const beep=(f,s,d)=>{const o=ctx.createOscillator(),g=ctx.createGain();o.connect(g);g.connect(ctx.destination);o.frequency.value=f;g.gain.setValueAtTime(0,s);g.gain.linearRampToValueAtTime(0.4,s+0.01);g.gain.linearRampToValueAtTime(0,s+d);o.start(s);o.stop(s+d+0.05);};
      beep(880,t,0.12);beep(1100,t+0.15,0.12);beep(1320,t+0.30,0.18);
      // Fallback de beep dura ~0.5s, aguarda antes de chamar onEnded
      if (onEnded) setTimeout(onEnded, 550);
    } catch(e2){ if (onEnded) setTimeout(onEnded, 550); }
  }
}

function pararSomNotificacao() {
  if (_notifTimeout) { clearTimeout(_notifTimeout); _notifTimeout=null; }
  if (_notifAudio) {
    try { _notifAudio.onended=null; _notifAudio.pause(); _notifAudio.currentTime=0; } catch(e){}
    _notifAudio=null;
  }
  _notifOrderId=null;
}


