function goTo(id) {
  document.querySelectorAll('.screen').forEach(el => el.classList.remove('active'));
  const el = document.getElementById(id);
  if (el) el.classList.add('active');
  currentScreen = id;
  if (id === 's-dash') renderDashboard();
  if (id === 's-store') renderStore();
  if (id === 's-checkout') renderCheckout();
  if (id === 's-ceo') renderCeo();
  // Rola o container da tela ativa (position:fixed usa scroll interno)
  const activeScreen = document.getElementById(id);
  if (activeScreen) activeScreen.scrollTop = 0;
}

// initRouting — apenas fallback para hash (#demo, #store-slug)
// O roteamento principal está em initRoutingAsync()
function initRouting() {
  const hash = window.location.hash;
  if (hash.startsWith('#store-')) {
    const slug = hash.replace('#store-','');
    const users = getUsers();
    const user = users.find(u => u.slug === slug && u.status === 'active');
    if (user) { currentUser = user; currentStoreSlug = slug; goTo('s-store'); return true; }
  }
  if (hash === '#demo' || hash === '#/demo') { openDemo(); return true; }
  return false;
}

