function updatePlanPrices() {
  const b = billingCycle === 'annual';
  document.getElementById('price-basico').textContent = b ? 'R$ 29,90' : 'R$ 39,90';
  document.getElementById('price-ultra').textContent = b ? 'R$ 79,90' : 'R$ 99,90';
  document.getElementById('annual-basico').style.display = b ? 'block' : 'none';
  document.getElementById('annual-ultra').style.display = b ? 'block' : 'none';
}
function selectPlan(plan) {
  selectedPlan = plan;
  document.getElementById('plan-basico').classList.toggle('selected', plan==='basico');
  document.getElementById('plan-ultra').classList.toggle('selected', plan==='ultra');
  const info = document.getElementById('plan-selected-info');
  const price = billingCycle === 'annual' ? (plan === 'basico' ? 'R$ 29,90/mês' : 'R$ 79,90/mês') : (plan === 'basico' ? 'R$ 39,90/mês' : 'R$ 99,90/mês');
  info.style.display = 'block';
  document.getElementById('psi-title').textContent = (plan === 'basico' ? 'Plano Básico — ' : 'Plano Ultra — ') + price;
  document.getElementById('psi-desc').textContent = plan === 'basico' ? 'Cardápio digital completo com pedidos ilimitados.' : 'Tudo do Básico + Financeiro, relatórios 90 dias e IA de automação.';
}
function goToMercadoPago() {
  if (!selectedPlan) { alert('Selecione um plano primeiro'); return; }
  if (!window._pendingReg) { goTo('s-register'); return; }
  const price = selectedPlan === 'basico' ? (billingCycle === 'annual' ? 29.90 : 39.90) : (billingCycle === 'annual' ? 79.90 : 99.90);
  // Em produção: redireciona para o Mercado Pago via backend
  // window.location.href = '/api/subscribe?plan='+selectedPlan+'&billing='+billingCycle;
  alert('Em produção isto abre o Mercado Pago.\n\nPlano ' + (selectedPlan==='basico'?'Básico':'Ultra') + ' · R$ ' + price.toFixed(2).replace('.',',') + '/mês\n\nUse "Simular pagamento" para testar agora.');
}
function simulatePayment() {
  const reg = window._pendingReg;
  if (!reg || !reg.name) { alert('Dados do cadastro não encontrados. Volte e preencha o formulário.'); goTo('s-register'); return; }
  if (!selectedPlan) { alert('Selecione um plano.'); return; }
  const slug = gerarSlug(reg.name);
  const newUser = {
    id: Date.now().toString(),
    name: reg.name, desc: reg.desc||'', emoji: '🍔', color: '#E8410A',
    slug, logo: reg.logo||null, email: reg.email, pass: reg.pass,
    whatsapp: digits(reg.wp||'5511999999999'),
    plan: selectedPlan, status: 'pending', dueDate: getDueDate(),
    payMethod: 'Mercado Pago', since: new Date().toISOString().slice(0,10),
    doc: reg.doc||'', orders: [], menuItems: [], flashItems: [], welcome: 'Seja bem-vindo!'
  };
  const solics = getSolicitations();
  solics.push({...newUser, submittedAt: new Date().toLocaleDateString('pt-BR')});
  setSolicitations(solics);

  // Salva como pendente no Supabase para o CEO ver de qualquer celular
  const db = getSupa();
  if (db) {
    db.from('estabelecimentos').insert({
      name: newUser.name, doc: newUser.doc||'', email: newUser.email,
      pass: newUser.pass, password_plain: newUser.pass,
      whatsapp: newUser.whatsapp||'', descricao: newUser.desc||'',
      slug: newUser.slug, emoji: '🍔', color: '#E8410A',
      plan_type: 'ultra', status: 'pending',
      logo_url: newUser.logo||null, created_at: new Date().toISOString()
    }).then(({error}) => {
      if (error) console.warn('Cadastro Supabase erro:', error.message);
    });
  }

  window._pendingReg = null;
  document.getElementById('pend-email').textContent = reg.email;
  goTo('s-pending');
}
function getDueDate() {
  const d = new Date();
  d.setMonth(d.getMonth() + (billingCycle === 'annual' ? 12 : 1));
  return d.toLocaleDateString('pt-BR');
}

// ─── DASHBOARD ──────────────────────────────────────────────────────────
async function renderDashboard() {
  if (!currentUser) return;

  // Sincroniza dados do estabelecimento do Supabase (pega sempre a versão mais recente)
  const db = getSupa();
  if (db && currentUser.id?.includes('-')) {
    try {
      const { data: dadosSupa } = await db
        .from('estabelecimentos')
        .select('name, descricao, slug, emoji, color, logo_url, whatsapp, address, flash_items, prep_time, delivery_enabled, pickup_enabled, delivery_fee, is_open, horarios')
        .eq('id', currentUser.id)
        .single();
      if (dadosSupa) {
        // Atualiza dados locais com o que está no banco (respeita edições de outros dispositivos)
        currentUser.name = dadosSupa.name || currentUser.name;
        currentUser.desc = dadosSupa.descricao || currentUser.desc;
        currentUser.slug = dadosSupa.slug || currentUser.slug;
        currentUser.emoji = dadosSupa.emoji || currentUser.emoji;
        currentUser.color = dadosSupa.color || currentUser.color;
        currentUser.logo = dadosSupa.logo_url || currentUser.logo;
        currentUser.whatsapp = dadosSupa.whatsapp || currentUser.whatsapp;
        currentUser.address = dadosSupa.address || currentUser.address;
        currentUser.prepTime = dadosSupa.prep_time || currentUser.prepTime || '30';
        if (dadosSupa.delivery_enabled !== undefined) currentUser.deliveryEnabled = dadosSupa.delivery_enabled;
        if (dadosSupa.pickup_enabled !== undefined) currentUser.pickupEnabled = dadosSupa.pickup_enabled;
        currentUser.deliveryFee = Number(dadosSupa.delivery_fee || 0);
        saveCurrentUser(); // persiste localmente
      }
    } catch(e) { console.warn('Sync Supabase erro:', e); }
  }

  const u = currentUser;
  document.getElementById('dash-sname').textContent = u.name;
  const slug = u.slug || 'demo';
  document.getElementById('dash-link').textContent = 'pediway.com.br/restaurante/' + slug;
  document.getElementById('st-items').textContent = (u.menuItems||[]).filter(i=>i.available).length;
  document.getElementById('st-plan').textContent = u.plan === 'ultra' ? 'Ultra' : 'Básico';
  const isUltra = u.plan === 'ultra';
  const tbFin = document.getElementById('tb-fin');
  if (!isUltra) tbFin.classList.add('locked'); else tbFin.classList.remove('locked');
  document.getElementById('fin-lock-banner').style.display = isUltra ? 'none' : 'flex';
  document.getElementById('fin-content').style.display = isUltra ? 'block' : 'none';

  // Carrega pedidos do Supabase se a loja tem ID real (db já declarado acima)
  if (db && u.id && u.id.includes('-')) {
    try {
      const { data: pedidosSupa } = await db
        .from('orders').select('*')
        .eq('establishment_id', u.id)
        .order('created_at', { ascending: false })
        .limit(50);
      if (pedidosSupa && pedidosSupa.length > 0) {
        u.orders = pedidosSupa.map(p => ({
          supaId: p.id,
          id: '#' + String(++orderCounter).padStart(4,'0'),
          client: p.client_name, phone: p.client_phone,
          address: p.address, delivery: p.delivery_type,
          items: typeof p.items === 'string' ? JSON.parse(p.items) : (p.items || []),
          payment: p.payment_method, total: Number(p.total),
          status: p.status,
          time: formatarTempo(p.created_at), ts: new Date(p.created_at).getTime()
        }));
        saveCurrentUser();
      }
    } catch(e) { console.warn('Erro ao carregar pedidos:', e); }

    // Carrega itens do cardápio do Supabase
    try {
      const { data: itensSupa } = await db
        .from('menu_items')
        .select('*')
        .eq('establishment_id', u.id)
        .order('category');
      if (itensSupa && itensSupa.length > 0) {
        u.menuItems = itensSupa.map(i => ({
          supaId: i.id, id: i.id,
          name: i.name, desc: i.descricao || '',
          price: Number(i.price), cat: i.category || 'Geral',
          emoji: i.emoji || '🍔', photo: i.photo_url || null,
          available: i.available
        }));
        saveCurrentUser();
      }
    } catch(e) { console.warn('Erro ao carregar cardápio:', e); }
  }

  const orders = u.orders || [];
  const todayOrders = orders.filter(o => o.status !== 'done');
  document.getElementById('st-today').textContent = todayOrders.length;
  const rev = orders.reduce((s,o)=>s+o.total, 0);
  document.getElementById('st-rev').textContent = 'R$ ' + rev.toFixed(2).replace('.',',');

  // Abre na aba Pedidos por padrão
  switchTab('t-orders');
  carregarOpcoesEntrega();
  carregarTempo();
  carregarStatusLoja();
  carregarHorarios();
  renderMenuGrid(); renderOrdersList(); renderOverviewOrders(); renderFlashAdmin();
  updateStoreEmojiPicker();
  if (isUltra) renderFinanceiro('hoje');

  // Inicia escuta de novos pedidos — pequeno delay garante que Supabase está pronto
  setTimeout(iniciarRealtimePedidos, 500);
}

function formatarTempo(isoStr) {
  if (!isoStr) return 'agora';
  const diff = Math.floor((Date.now() - new Date(isoStr).getTime()) / 60000);
  if (diff < 1) return 'agora';
  if (diff < 60) return `há ${diff} min`;
  return `há ${Math.floor(diff/60)}h`;
}

function switchTab(id) {
  document.querySelectorAll('.tb').forEach(b=>b.classList.remove('active'));
  document.querySelectorAll('.tp').forEach(p=>p.classList.remove('active'));
  const panel = document.getElementById(id);
  if (panel) panel.classList.add('active');
  const tabs = ['t-orders','t-ov','t-menu','t-flash','t-financeiro','t-settings'];
  const btns = document.querySelectorAll('.tb');
  tabs.forEach((t,i)=>{if(btns[i]) btns[i].classList.toggle('active', t===id);});
}

function switchTabFin() {
  if (!currentUser) return;
  if (currentUser.plan !== 'ultra') {
    showNotif('Plano Básico','Este recurso requer o Plano Ultra 🚀');
    return;
  }
  switchTab('t-financeiro');
}

